import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"天堂之门","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/天堂之门.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/天堂之门.md"}'),d={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/天堂之门.md"};function p(l,a,_,i,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"天堂之门",tabindex:"-1"},[s("天堂之门 "),e("a",{class:"header-anchor",href:"#天堂之门","aria-label":'Permalink to "天堂之门"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001E")])])],-1),o('<h1 id="天堂之门-1" tabindex="-1">天堂之门 <a class="header-anchor" href="#天堂之门-1" aria-label="Permalink to &quot;天堂之门&quot;">​</a></h1><p>天堂之门</p><p>A+11300</p><p>替身数据：<br> 破坏力D<br> 速度B<br> 射程B<br> 持续力B<br> 精密度C<br> 成长性A</p><p>检定属性：智力<br> 替身外貌：主体为白色搭配黄色线条，外表是个穿着礼服头戴高帽的小孩，形象来自于岸边露伴的漫画《红黑少年》的主角。 <br> 能力描述：<br> 拥有该替身者，可以以一个标准动作唤出替身冲向范围内的一名目标，随后使用者以智力+专注+专业：替身使用+专业：精神力进行一次攻击检定，目标以反射检定进行对抗，若使用者对抗成功，则替身成功触摸到对方，对方将因此变为无法行动但仍具有自我意识的书籍，你可以翻阅这本书籍，以知晓其记忆，这相当于对方以让你查阅的方式对你述说了自己的记忆，所以自己不知晓的事情在书中不会出现，并且一般来说书中显示的是生前的记忆，死后的记忆不会显示，书的文字取决于对象的常用语言，所以有时也会出现看不懂书中的文字的情况，这是一个心灵来源的S级支配效果，变成书的状态至多持续2小时，之后自动解除变书状态。替身拥有者可以以自由动作解除变书状态，若替身拥有者可以对变成书的被害人进行书写，则可以用自由动作在书中写下无法违抗的命令，也可以撕掉一些书页来令对方忘记部分记忆，这视为S级支配效果。也可以书写其本身无法执行的指令，在主神空间这种没有起因制造结果的事情基本上是主神才能做到的，因此对于获得这项能力的轮回者，若选择书写其本身无法执行的指令，则会在被书写者与世间万物的共同作用下令写下的指令被执行，例如写下身体以70码的速度往后面飞去，就可能是一辆飞来的隐形战车将其撞飞。这是一个S级的命运效果，因此实在过于不可能的指令也存在不会生效的可能。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
